/**
 * E2E Test: Blog & Content Pages
 * Verifica listagem do blog, artigos individuais, navegação e estrutura de conteúdo.
 */

import { test, expect } from '@playwright/test';

// Known blog slugs from the marketing page
const BLOG_SLUGS = [
  'como-criar-videos-treinamento-nr',
  'tendencias-treinamento-corporativo-2026',
  'avatares-ia-treinamento',
  'guia-completo-nr-10-video',
  'roi-videos-treinamento-ia',
  'tts-vozes-naturais-portugues',
];

// -------------------------------------------------------
// Blog listing page
// -------------------------------------------------------
test.describe('Blog Listing', () => {
  test('Blog page loads without server error', async ({ page }) => {
    const response = await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    expect(response).not.toBeNull();
    expect(response!.status()).toBeLessThan(500);
  });

  test('Blog page has a heading', async ({ page }) => {
    await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    const heading = page.locator('h1, h2, [role="heading"]');
    await expect(heading.first()).toBeAttached({ timeout: 10_000 });
  });

  test('Blog page shows article cards', async ({ page }) => {
    await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    // Should have at least one article card or link
    const articles = page.locator('article, [class*="card"], a[href*="/blog/"]');
    const count = await articles.count();
    expect(count).toBeGreaterThan(0);
  });

  test('Blog article links point to valid slugs', async ({ page }) => {
    await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    const articleLinks = page.locator('a[href*="/blog/"]');
    const count = await articleLinks.count();

    // At least some should exist
    expect(count).toBeGreaterThan(0);

    // Verify link hrefs are well-formed (no accented characters, no spaces)
    for (let i = 0; i < Math.min(count, 6); i++) {
      const href = await articleLinks.nth(i).getAttribute('href');
      expect(href).toBeTruthy();
      // Slug should be URL-safe: no accents, no spaces, lowercase
      const slug = href!.replace('/blog/', '').replace(/\/$/, '');
      if (slug) {
        expect(slug).toMatch(/^[a-z0-9-]+$/);
      }
    }
  });

  test('Blog page has meta description for SEO', async ({ page }) => {
    await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title.length).toBeGreaterThan(3);
  });
});

// -------------------------------------------------------
// Individual blog articles
// -------------------------------------------------------
test.describe('Blog Articles', () => {
  for (const slug of BLOG_SLUGS) {
    test(`Article "${slug}" loads without server error`, async ({ page }) => {
      const response = await page.goto(`/blog/${slug}`, { waitUntil: 'domcontentloaded' });
      expect(response).not.toBeNull();
      expect(response!.status()).toBeLessThan(500);
    });
  }

  test('Article page has heading and content', async ({ page }) => {
    await page.goto(`/blog/${BLOG_SLUGS[0]}`, { waitUntil: 'domcontentloaded' });
    // Should have a heading
    const heading = page.locator('h1');
    await expect(heading.first()).toBeAttached({ timeout: 10_000 });

    // Should have substantial text content
    const bodyText = await page.textContent('body');
    expect(bodyText).toBeTruthy();
    expect(bodyText!.length).toBeGreaterThan(200);
  });

  test('Article page has back link to blog listing', async ({ page }) => {
    await page.goto(`/blog/${BLOG_SLUGS[0]}`, { waitUntil: 'domcontentloaded' });
    // Should have a link back to the blog listing
    const backLink = page.locator(
      'a[href="/blog"], a[href*="/blog"]:has-text("Voltar"), a:has-text("Blog"), a:has-text("← ")'
    );
    const count = await backLink.count();
    // It's nice to have, but not critical
    if (count > 0) {
      expect(count).toBeGreaterThan(0);
    }
  });

  test('Article page has proper meta tags', async ({ page }) => {
    await page.goto(`/blog/${BLOG_SLUGS[0]}`, { waitUntil: 'domcontentloaded' });
    const title = await page.title();
    expect(title).toBeTruthy();
    expect(title.length).toBeGreaterThan(5);
  });
});

// -------------------------------------------------------
// Blog navigation flow
// -------------------------------------------------------
test.describe('Blog Navigation', () => {
  test('Can navigate from blog listing to article', async ({ page }) => {
    await page.goto('/blog', { waitUntil: 'domcontentloaded' });
    const firstArticleLink = page.locator('a[href*="/blog/"]').first();
    const count = await firstArticleLink.count();
    if (count > 0) {
      await firstArticleLink.click();
      await page.waitForLoadState('domcontentloaded');
      expect(page.url()).toContain('/blog/');
      // Should load without error
      const heading = page.locator('h1, h2');
      await expect(heading.first()).toBeAttached({ timeout: 10_000 });
    }
  });

  test('Non-existent blog article returns 404', async ({ page }) => {
    const response = await page.goto('/blog/artigo-que-nao-existe-xyz', {
      waitUntil: 'domcontentloaded',
    });
    const status = response?.status() ?? 200;
    // Either proper 404 or soft 404 (with "not found" content)
    if (status === 404) {
      expect(status).toBe(404);
    } else {
      const bodyText = await page.textContent('body');
      const isNotFound =
        bodyText?.includes('404') ||
        bodyText?.includes('não encontrad') ||
        bodyText?.includes('not found');
      expect(status).toBeLessThan(500);
    }
  });
});
